+}
+
+// ── Helpers ──────────────────────────────────────────────────────────────────
+
+fn report(name: &str, value: f64, unit: &str, budget: f64) {
+    let status = if value <= budget {
+        "\x1b[32mOK\x1b[0m"
+    } else {
+        "\x1b[33mSLOW\x1b[0m"
+    };
