+fn hit(doc_id: &str, score: f32, index: u32) -> VectorHit {
+    VectorHit {
+        index,
+        score,
+        doc_id: doc_id.to_owned(),
+    }
+}
+
+fn scored(doc_id: &str, score: f32) -> ScoredResult {
+    ScoredResult {
+        doc_id: doc_id.to_owned(),
+        score,
+        source: ScoreSource::Hybrid,
+        fast_score: None,
+        quality_score: None,
+        lexical_score: None,
+        rerank_score: None,
+        metadata: None,
+    }
+}
