+        assert_eq!(r1.len(), r2.len());
+        for (a, b) in r1.iter().zip(r2.iter()) {
+            assert_eq!(a.doc_id, b.doc_id, "result order should be deterministic");
+            assert!(
+                (a.score - b.score).abs() < 1e-6,
+                "scores should match: {} vs {}",
+                a.score,
+                b.score
+            );
+        }
+    });
+}
